/* ===== Vars ===== */
:root{
  --outer-font:"TsangerXWZ","Microsoft YaHei",sans-serif;
  --main-font:"Zhuque Fangsong (technical preview)","Microsoft YaHei",sans-serif;
  --header-font:'Allura',cursive;

  --container-width:600px; --border-radius:16px;
