  --blend-color:#f4efe6; --item-bg:rgba(255,255,255,.48);
  --item-hover-bg:rgba(255,255,255,.72); --item-border:rgba(160,165,170,.18);
  --blend-opacity:.11; --noise-opacity:.035; --fiber-opacity:.06;
